30		generateAppJwt(): string {
31			const appId = this.configService.get<string>({ key: GITHUB_APP_ID });
32			const rawKey = this.configService.get<string>({ key: GITHUB_APP_PRIVATE_KEY });
33			const privateKey = rawKey.replace(/\\n/g, '\n');
34	
35			const now = Math.floor(Date.now() / 1000);
36			const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString(
37				'base64url',
38			);
39			const payload = Buffer.from(
40				JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId }),
41			).toString('base64url');
42			const data = `${header}.${payload}`;
43	
44			const sign = createSign('RSA-SHA256');
45			sign.update(data);
46			const signature = sign.sign(privateKey, 'base64url');
