import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Queue } from 'bullmq';

import { GithubRepoModel } from '@modules/github/db/github-repos.model';

@Injectable()
export class GithubBackfillService {
	private readonly logger = new Logger(GithubBackfillService.name);

	constructor(
		private readonly repoModel: GithubRepoModel,
		@InjectQueue('github') private readonly githubQueue: Queue,
	) {}

	async triggerBackfill({
		installationDbId,
		installationId,
	}: {
		installationDbId: string;
		installationId: number;
	}): Promise<void> {
		try {
			const repos = await this.repoModel.findByInstallationId({ installationId: installationDbId });
			for (const repo of repos) {
				await this.githubQueue.add(
					'backfill_repo',
					{
						installationDbId,
						installationId,
						repoDbId: repo._id,
						repoFullName: repo.full_name,
					},
					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
				);
			}
			this.logger.debug(`Enqueued backfill for ${repos.length} repos in installation ${installationDbId}`);
		} catch (error) {
			this.logger.error(`Failed to trigger backfill for installation ${installationDbId}: ${(error as Error).message}`);
			throw error;
		}
	}
}

