22	
23		async upsertMany({
24			installationId,
25			repos,
26		}: {
27			installationId: string;
28			repos: IGithubApiRepo[];
29		}): Promise<void> {
30			if (repos.length === 0) return;
31	
32			try {
33				const rows = repos.map((repo) => ({
34					_id: randomUUID(),
35					installation_id: installationId,
36					github_repo_id: repo.id,
37					name: repo.name,
38					full_name: repo.full_name,
39					private: repo.private,
40					default_branch: repo.default_branch,
41					created_at: this.knexWrite.fn.now(),
42					updated_at: this.knexWrite.fn.now(),
43				}));
44	
45				await this.knexWrite<IGithubRepoBase>(this.tableName)
46					.insert(rows)
47					.onConflict('github_repo_id')
48					.merge([
49						'installation_id',
50						'name',
51						'full_name',
52						'private',
53						'default_branch',
54						'updated_at',
55					]);
