	private async handleBackfillRepo({ data }: { data: IBackfillRepoJob }): Promise<void> {
		const { installationDbId, installationId, repoDbId, repoFullName } = data;
		this.logger.debug(`Starting backfill for repo ${repoFullName}`);
		const token = await this.githubAppService.getInstallationToken({ installationId });
		const parts = repoFullName.split('/');
		const owner = parts[0] ?? '';
		const repo = parts[1] ?? '';
		await this.backfillCommits({ installationDbId, repoDbId, repoFullName, owner, repo, token });
		await this.backfillPullRequests({ installationDbId, repoDbId, repoFullName, owner, repo, token });
		this.logger.debug(`Backfill complete for repo ${repoFullName}`);
	}

	private async backfillCommits({
		installationDbId,
		repoDbId,
		repoFullName,
		owner,
		repo,
		token,
	}: {
		installationDbId: string;
		repoDbId: string;
		repoFullName: string;
		owner: string;
		repo: string;
		token: string;
	}): Promise<void> {
		let page = 1;
		const perPage = 100;
		while (true) {
			const { data: commits } = await this.httpService.axiosRef.get<IGithubApiCommit[]>(
				`https://api.github.com/repos/${owner}/${repo}/commits`,
				{
					headers: {
						Authorization: `token ${token}`,
						Accept: 'application/vnd.github+json',
						'X-GitHub-Api-Version': '2022-11-28',
					},
					params: { per_page: perPage, page },
				},
			);
			if (commits.length === 0) break;
			await this.commitModel.upsertMany({
				commits: commits.map((c) => ({
					installation_id: installationDbId,
					repo_id: repoDbId,
					sha: c.sha,
					message: c.commit.message,
					author_login: c.author?.login ?? null,
					author_name: c.commit.author.name,
					author_email: c.commit.author.email,
					committed_at: new Date(c.commit.author.date),
					additions: c.stats?.additions ?? 0,
					deletions: c.stats?.deletions ?? 0,
					is_merge_commit: c.parents.length > 1,
				})),
			});
			if (commits.length < perPage) break;
			page++;
		}
		this.logger.debug(`Backfilled commits for ${repoFullName}`);
	}

	private async backfillPullRequests({
		installationDbId,
		repoDbId,
		repoFullName,
		owner,
		repo,
		token,
	}: {
		installationDbId: string;
		repoDbId: string;
		repoFullName: string;
		owner: string;
		repo: string;
		token: string;
	}): Promise<void> {
		let page = 1;
		const perPage = 100;
		while (true) {
			const { data: prs } = await this.httpService.axiosRef.get<IGithubApiPullRequest[]>(
				`https://api.github.com/repos/${owner}/${repo}/pulls`,
				{
					headers: {
						Authorization: `token ${token}`,
						Accept: 'application/vnd.github+json',
						'X-GitHub-Api-Version': '2022-11-28',
					},
					params: { state: 'all', per_page: perPage, page },
				},
			);
			if (prs.length === 0) break;
			for (const pr of prs) {
				await this.contributorModel.upsert({
					data: {
						installation_id: installationDbId,
						github_user_id: pr.user.id,
						github_login: pr.user.login,
					},
				});
				const saved = await this.pullRequestModel.upsert({
					data: {
						installation_id: installationDbId,
						repo_id: repoDbId,
						github_pr_id: pr.id,
						pr_number: pr.number,
						title: pr.title,
						state: pr.state as GithubPRState,
						author_login: pr.user.login,
						draft: pr.draft,
						merged: pr.merged,
						additions: pr.additions,
						deletions: pr.deletions,
						changed_files: pr.changed_files,
						commits_count: pr.commits,
						opened_at: new Date(pr.created_at),
						merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
						closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
					},
				});
				await this.backfillPrReviews({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
				await this.backfillPrReviewComments({ installationDbId, prDbId: saved._id, owner, repo, prNumber: pr.number, token });
			}
			if (prs.length < perPage) break;
			page++;
		}
		this.logger.debug(`Backfilled PRs for ${repoFullName}`);
	}

	private async backfillPrReviews({
		installationDbId,
		prDbId,
		owner,
		repo,
		prNumber,
		token,
	}: {
		installationDbId: string;
		prDbId: string;
		owner: string;
		repo: string;
		prNumber: number;
		token: string;
	}): Promise<void> {
		const { data: reviews } = await this.httpService.axiosRef.get<IGithubApiReview[]>(
			`https://api.github.com/repos/${owner}/${repo}/pulls/${prNumber}/reviews`,
			{
				headers: {
					Authorization: `token ${token}`,
					Accept: 'application/vnd.github+json',
					'X-GitHub-Api-Version': '2022-11-28',
				},
				params: { per_page: 100 },
			},
		);
		for (const review of reviews) {
			const normalizedState = review.state.toLowerCase();
			const validStates = ['approved', 'changes_requested', 'commented', 'dismissed'];
			if (!validStates.includes(normalizedState)) continue;
			await this.contributorModel.upsert({
				data: {
					installation_id: installationDbId,
					github_user_id: review.user.id,
					github_login: review.user.login,
				},
			});
			await this.reviewModel.upsert({
				data: {
					installation_id: installationDbId,
					pull_request_id: prDbId,
					github_review_id: review.id,
					reviewer_login: review.user.login,
					state: normalizedState as GithubReviewState,
					submitted_at: new Date(review.submitted_at),
				},
			});
		}
	}

	private async backfillPrReviewComments({
		installationDbId,
		prDbId,
		owner,
		repo,
		prNumber,
		token,
	}: {
		installationDbId: string;
		prDbId: string;
		owner: string;
		repo: string;
		prNumber: number;
		token: string;
	}): Promise<void> {
		const { data: comments } = await this.httpService.axiosRef.get<IGithubApiReviewComment[]>(
			`https://api.github.com/repos/${owner}/${repo}/pulls/${prNumber}/comments`,
			{
				headers: {
					Authorization: `token ${token}`,
					Accept: 'application/vnd.github+json',
					'X-GitHub-Api-Version': '2022-11-28',
				},
				params: { per_page: 100 },
			},
		);
		for (const comment of comments) {
			await this.contributorModel.upsert({
				data: {
					installation_id: installationDbId,
					github_user_id: comment.user.id,
					github_login: comment.user.login,
				},
			});
			await this.reviewCommentModel.upsert({
				data: {
					installation_id: installationDbId,
					pull_request_id: prDbId,
					github_comment_id: comment.id,
					author_login: comment.user.login,
					body: comment.body,
					path: comment.path,
					line: comment.line,
					commented_at: new Date(comment.created_at),
				},
			});
		}
	}
}

